mapper.select:
/* oms-master-owOrIf-sql-oracle.xml selectOrIfList */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT '0' AS CHK , A.OWKEY , O.OWNM AS OWKEYNM , A.EXTORDERTYPECD , A.EXTORDERTYPECD || ':' || ME.EXTORDERTYPENM AS EXTORDERTYPENM , A.HDDTDIV , A.HDDTDIV || ':' || DT.ORDERCOMDTNM AS HDDTDIVNM , A.IFCOL , C.COMMENTS AS IFCOLNM , A.COCOL , COALESCE(A.DELYN, 'N') AS DELYN , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY FROM TORDER_INFO_IF_MAPPING A JOIN TORDER_MST_IF_SET B ON A.OWKEY = B.OWKEY AND A.EXTORDERTYPECD = B.EXTORDERTYPECD AND A.HDDTDIV = B.HDDTDIV LEFT JOIN USER_COL_COMMENTS C ON B.IFTBNM = C.TABLE_NAME AND A.IFCOL = C.COLUMN_NAME LEFT JOIN USER_TAB_COLUMNS CI ON B.IFTBNM = CI.TABLE_NAME AND A.IFCOL = CI.COLUMN_NAME JOIN TORDER_MST_EXTERN ME ON A.OWKEY = ME.OWKEY AND A.EXTORDERTYPECD = ME.EXTORDERTYPECD JOIN TORDER_MST_ORCD_DT DT ON A.HDDTDIV = DT.ORDERCOMDTKEY AND DT.ORDERCOMHDKEY = 'HDDTDIV' AND DT.LAKEY = #{lakey} JOIN TORDER_MST_OW O ON A.OWKEY = O.OWKEY WHERE 1=1
AND #{SEARCH_CONDITION}
AND A.OWKEY = #{owkey}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY CI.COLUMN_ID
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

		SELECT COUNT(1)
		  FROM TORDER_INFO_IF_MAPPING	
    	 WHERE OWKEY = #{owkey}
    	   AND EXTORDERTYPECD = #{extordertypecd}
    	   AND HDDTDIV = #{hddtdiv}
    	   AND IFCOL = #{ifcol}

mapper.insert:
/* oms-master-owOrIf-sql-oracle.xml insertOwOrIf */
	INSERT INTO TORDER_INFO_IF_MAPPING
	(
	      OWKEY
		, EXTORDERTYPECD
		, HDDTDIV
		, IFCOL
		, COCOL
	    , DELYN
	    , INSERTDATE
	    , INSERTURKEY
	    , UPDATEDATE
	    , UPDATEURKEY
	)
	VALUES
	(
	      #{owkey}
		, #{extordertypecd}
		, #{hddtdiv}
		, #{ifcol}
		, #{cocol}
	    , #{delyn}
	    , #{sysdate}
	    , #{surkey}
	    , #{sysdate}
	    , #{surkey}
	)

mapper.update:
/* oms-master-owOrIf-sql-oracle.xml updateOwOrIf */
	UPDATE TORDER_INFO_IF_MAPPING
	   SET COCOL		= #{cocol}
	     , DELYN        = #{delyn}
	     , UPDATEDATE   = #{sysdate}
	     , UPDATEURKEY  = #{surkey}
	 WHERE OWKEY = #{owkey}
	   AND EXTORDERTYPECD = #{extordertypecd}
	   AND HDDTDIV = #{hddtdiv}
	   AND IFCOL = #{ifcol}
